-- ============================================================
-- Quiz Seed: Job Chapters 11–21
-- Target table: chapter_quizzes
-- Difficulties: kids (3 Qs), teens (5 Qs), adults (8 Qs)
-- correct_answer is always 'a'
-- ============================================================

-- ═══ Job Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 11, 'kids', 1, 'Who gave the first speech in Job chapter 11?', 'Zophar', 'Eliphaz', 'Bildad', 'Elihu', 'a', 'Zophar the Naamathite answered and spoke in Job chapter 11 (Job 11:1).'),
('Job', 11, 'kids', 2, 'What did Zophar say about God''s wisdom?', 'It is very high and cannot be fully known', 'It is shared with all people', 'It belongs only to angels', 'It was given to Job', 'a', 'Zophar declared that God''s wisdom is higher than heaven and deeper than hell (Job 11:8).'),
('Job', 11, 'kids', 3, 'What did Zophar tell Job to do so that things would go well for him?', 'Prepare his heart and stretch out his hands to God', 'Build an altar and offer a sacrifice', 'Go on a long journey', 'Ask his friends for help', 'a', 'Zophar told Job, "If thou prepare thine heart, and stretch out thine hands toward him" things would go well (Job 11:13).'),
-- Teens
('Job', 11, 'teens', 1, 'What famous question does Zophar ask about searching out God in Job 11:7?', 'Canst thou by searching find out God?', 'Can a man be righteous before God?', 'Who can number the stars?', 'Where wast thou when I laid the foundations?', 'a', 'Zophar asks, "Canst thou by searching find out God? canst thou find out the Almighty unto perfection?" (Job 11:7).'),
('Job', 11, 'teens', 2, 'How does Zophar describe the measure of God''s wisdom in Job 11:9?', 'Longer than the earth and broader than the sea', 'Higher than the heavens and deeper than the ocean', 'Wider than the desert and taller than the mountains', 'Greater than all the stars combined', 'a', 'The measure thereof is longer than the earth, and broader than the sea (Job 11:9).'),
('Job', 11, 'teens', 3, 'What does Zophar say God can perceive about a man in Job 11:11?', 'Vain men and wickedness', 'Only outward deeds', 'A man''s wealth and poverty', 'A man''s words alone', 'a', 'He knoweth vain men: he seeth wickedness also; will he not then consider it? (Job 11:11).'),
('Job', 11, 'teens', 4, 'What image does Zophar use to describe a foolish man gaining understanding in Job 11:12?', 'A wild ass''s colt born a man', 'A blind man seeing light', 'A stone becoming water', 'A dry tree bearing fruit', 'a', 'For vain man would be wise, though man be born like a wild ass''s colt (Job 11:12).'),
('Job', 11, 'teens', 5, 'What does Zophar promise Job if he repents in Job 11:17?', 'His age shall be clearer than the noonday', 'God will restore his wealth double', 'His enemies will flee', 'His children will return', 'a', 'Thine age shall be clearer than the noonday; thou shalt shine forth, thou shalt be as the morning (Job 11:17).'),
-- Adults
('Job', 11, 'adults', 1, 'What charge does Zophar level against Job in Job 11:2-3?', 'That a multitude of words should not go unanswered and Job''s boasting should make men hold their peace', 'That Job has blasphemed God openly', 'That Job has sinned against his neighbors', 'That Job has forsaken the law of Moses', 'a', 'Should not the multitude of words be answered? and should a man full of talk be justified? (Job 11:2).'),
('Job', 11, 'adults', 2, 'What does Zophar wish God would do in Job 11:5-6?', 'That God would speak and show Job the secrets of wisdom', 'That God would restore Job''s health', 'That God would silence Job''s friends', 'That God would send rain to bless Job', 'a', 'But oh that God would speak...and shew thee the secrets of wisdom, that they are double to that which is (Job 11:5-6).'),
('Job', 11, 'adults', 3, 'How does Zophar describe the dimensions of God''s knowledge in Job 11:8-9?', 'It is as high as heaven, deep as hell, longer than earth, broader than sea', 'It is infinite in all directions beyond measure', 'It fills the north and south with equal light', 'It encompasses all time from creation to eternity', 'a', 'It is as high as heaven...deeper than hell...The measure thereof is longer than the earth, and broader than the sea (Job 11:8-9).'),
('Job', 11, 'adults', 4, 'What action does Zophar say God can perform that no one can hinder in Job 11:10?', 'If he cut off, and shut up, or gather together, then who can hinder him?', 'If he sends famine no man can stop it', 'If he speaks the mountains crumble', 'If he commands the sea it obeys', 'a', 'If he cut off, and shut up, or gather together, then who can hinder him? (Job 11:10).'),
('Job', 11, 'adults', 5, 'What specific acts of repentance does Zophar call Job to in Job 11:13-14?', 'Prepare thine heart, stretch out hands, put iniquity away, and let not wickedness dwell in thy tabernacles', 'Fast forty days and make a burnt offering', 'Humble himself before his friends and confess his sin publicly', 'Return to the land of his fathers and rebuild his altars', 'a', 'If thou prepare thine heart, and stretch out thine hands toward him; If iniquity be in thine hand, put it far away (Job 11:13-14).'),
('Job', 11, 'adults', 6, 'What security does Zophar promise Job after repentance in Job 11:18-19?', 'Thou shalt be secure because there is hope, and thou shalt take thy rest in safety with none to make thee afraid', 'God will rebuild his house and restore his lands', 'His enemies will become his servants', 'He will receive a new name and a new covenant', 'a', 'Thou shalt be secure, because there is hope; yea, thou shalt dig about thee, and thou shalt take thy rest in safety (Job 11:18-19).'),
('Job', 11, 'adults', 7, 'What fate does Zophar describe for the wicked in Job 11:20?', 'The eyes of the wicked shall fail, and their hope shall be as the giving up of the ghost', 'The wicked shall be swallowed by the earth', 'Their children shall suffer for their sin', 'They shall be driven into the wilderness', 'a', 'But the eyes of the wicked shall fail, and they shall not escape, and their hope shall be as the giving up of the ghost (Job 11:20).'),
('Job', 11, 'adults', 8, 'Theologically, what is the core error of Zophar''s argument in chapter 11?', 'He assumes Job''s suffering is direct proof of hidden sin, misapplying the doctrine of divine retribution', 'He denies the resurrection of the dead', 'He claims God cannot forgive sin', 'He teaches that wisdom belongs only to the educated', 'a', 'Zophar insists God exacts less than Job''s iniquity deserves (Job 11:6), wrongly equating suffering with personal sin.');

-- ═══ Job Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 12, 'kids', 1, 'What did Job say about himself compared to his friends in Job 12:3?', 'I am not inferior to you', 'I am wiser than all of you', 'I have suffered more than you', 'I have prayed longer than you', 'a', 'Job declared, "But I have understanding as well as you; I am not inferior to you" (Job 12:3).'),
('Job', 12, 'kids', 2, 'What did Job say even the animals and birds can teach in Job 12:7?', 'That God made all things', 'That God feeds the hungry', 'That rain falls on the earth', 'That the sun rises every day', 'a', 'Job said, "Ask now the beasts, and they shall teach thee; and the fowls of the air, and they shall tell thee" (Job 12:7).'),
('Job', 12, 'kids', 3, 'Who does Job say holds the life of every creature in Job 12:10?', 'God', 'Angels', 'Wise men', 'Kings', 'a', 'In whose hand is the soul of every living thing, and the breath of all mankind (Job 12:10).'),
-- Teens
('Job', 12, 'teens', 1, 'How does Job describe himself mockingly in Job 12:4?', 'As one who is mocked by his neighbour, a just, upright man', 'As the weakest man in the land', 'As a fool who spoke too boldly', 'As a stranger in his own house', 'a', 'I am as one mocked of his neighbour, who calleth upon God, and he answereth him: the just upright man is laughed to scorn (Job 12:4).'),
('Job', 12, 'teens', 2, 'What observation does Job make about the prosperous and the thief in Job 12:6?', 'The tabernacles of robbers prosper and they that provoke God are secure', 'The thief is always caught and punished', 'Wealth comes only to the righteous', 'God punishes the wicked without delay', 'a', 'The tabernacles of robbers prosper, and they that provoke God are secure; into whose hand God bringeth abundantly (Job 12:6).'),
('Job', 12, 'teens', 3, 'What does Job say the ear does in Job 12:11?', 'Trieth words as the mouth tasteth meat', 'Hears only what the heart desires', 'Listens for the voice of God', 'Receives wisdom from the aged', 'a', 'Doth not the ear try words? and the mouth taste his meat? (Job 12:11).'),
('Job', 12, 'teens', 4, 'What does Job say God does to counsellors in Job 12:17?', 'He leadeth counsellors away spoiled', 'He gives counsellors great wisdom', 'He sends counsellors to comfort the afflicted', 'He rewards counsellors with long life', 'a', 'He leadeth counsellors away spoiled, and maketh the judges fools (Job 12:17).'),
('Job', 12, 'teens', 5, 'What does Job say God does to nations in Job 12:23?', 'He increaseth the nations and destroyeth them', 'He blesses the faithful nations forever', 'He sets all nations at peace', 'He divides the nations among the angels', 'a', 'He increaseth the nations, and destroyeth them: he enlargeth the nations, and straiteneth them again (Job 12:23).'),
-- Adults
('Job', 12, 'adults', 1, 'How does Job characterize the wisdom his friends offer in Job 12:2?', 'No doubt but ye are the people, and wisdom shall die with you', 'Your wisdom is borrowed from your fathers', 'You speak as men who have never suffered', 'Your counsel is empty and without foundation', 'a', 'No doubt but ye are the people, and wisdom shall die with you (Job 12:2).'),
('Job', 12, 'adults', 2, 'What does Job observe about the contempt shown to those who are righteous and call on God in Job 12:4-5?', 'The just man who calls on God is mocked, while the prosperous despise the misfortune of others', 'The righteous are honored above all others', 'Those who pray are always vindicated quickly', 'God silences those who mock the righteous', 'a', 'The just upright man is laughed to scorn...He that is ready to slip with his feet is as a lamp despised in the thought of him that is at ease (Job 12:4-5).'),
('Job', 12, 'adults', 3, 'What four aspects of nature does Job cite in Job 12:7-9 as witnesses to God''s sovereign work?', 'Beasts, fowls of the air, the earth, and the fishes of the sea', 'Mountains, rivers, stars, and clouds', 'Wind, fire, rain, and earthquake', 'Trees, grass, stones, and sand', 'a', 'Ask the beasts, the fowls of the air, speak to the earth, and the fishes of the sea shall declare unto thee (Job 12:7-8).'),
('Job', 12, 'adults', 4, 'What theological principle does Job assert in Job 12:10 about all living things?', 'In God''s hand is the soul of every living thing and the breath of all mankind', 'God gives life only to those who obey him', 'All life returns to the dust by God''s command', 'The breath of life belongs to the angels', 'a', 'In whose hand is the soul of every living thing, and the breath of all mankind (Job 12:10).'),
('Job', 12, 'adults', 5, 'How does Job describe God''s power over kings and judges in Job 12:17-18?', 'He leadeth counsellors spoiled, makes judges fools, looses the bond of kings, and girds them with a girdle', 'He crowns the humble and casts down the proud', 'He establishes kingdoms for a thousand generations', 'He gives wisdom only to those who fear him', 'a', 'He leadeth counsellors away spoiled...He looseth the bond of kings, and girdeth their loins with a girdle (Job 12:17-18).'),
('Job', 12, 'adults', 6, 'What does Job say God does to the deep darkness in Job 12:22?', 'He discovereth deep things out of darkness and bringeth out to light the shadow of death', 'He fills the darkness with his glory', 'He commands darkness to flee before the righteous', 'He hides his mysteries in the deep', 'a', 'He discovereth deep things out of darkness, and bringeth out to light the shadow of death (Job 12:22).'),
('Job', 12, 'adults', 7, 'How does Job describe what God does to the leaders of the earth in Job 12:24-25?', 'He taketh away the heart of the chief people and causeth them to wander in a wilderness where there is no way, and they grope in darkness', 'He rewards faithful leaders with long reigns', 'He sends angels to guide every king', 'He writes laws on the hearts of rulers', 'a', 'He taketh away the heart of the chief people...and causeth them to wander in a wilderness where there is no way. They grope in the dark (Job 12:24-25).'),
('Job', 12, 'adults', 8, 'What is the rhetorical purpose of Job''s appeal to creation''s testimony in Job 12:7-9?', 'To prove that even the beasts know God''s sovereign hand is behind all things, undermining his friends'' claim that suffering equals sin', 'To show that Job studied natural philosophy', 'To demonstrate that animals have greater wisdom than men', 'To argue that God does not intervene in human affairs', 'a', 'Job appeals to the beasts and earth as witnesses that "the hand of the LORD hath wrought this" (Job 12:9), asserting God''s sovereignty over all including his own suffering.');

-- ═══ Job Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 13, 'kids', 1, 'What did Job call his three friends in Job 13:4?', 'Forgers of lies and physicians of no value', 'Wise counsellors and good teachers', 'Faithful friends and true helpers', 'Messengers of comfort', 'a', 'Job told his friends, "Ye are forgers of lies, ye are all physicians of no value" (Job 13:4).'),
('Job', 13, 'kids', 2, 'What bold thing did Job want to do before God in Job 13:3?', 'Speak to the Almighty and reason with God', 'Build an altar and offer a great sacrifice', 'Sing praises to God all night', 'Ask God to send an angel to help him', 'a', 'Job said, "Surely I would speak to the Almighty, and I desire to reason with God" (Job 13:3).'),
('Job', 13, 'kids', 3, 'What famous statement of trust did Job make in Job 13:15?', 'Though he slay me, yet will I trust in him', 'God is my shepherd and I shall not want', 'The Lord gave and the Lord hath taken away', 'He restoreth my soul and leadeth me', 'a', 'Though he slay me, yet will I trust in him: but I will maintain mine own ways before him (Job 13:15).'),
-- Teens
('Job', 13, 'teens', 1, 'What does Job say about the wisdom of his friends in Job 13:2?', 'What ye know, the same do I know also; I am not inferior unto you', 'Your wisdom is greater than mine but misapplied', 'You know the ways of God but speak falsely', 'You have forgotten the counsel of the aged', 'a', 'What ye know, the same do I know also: I am not inferior unto you (Job 13:2).'),
('Job', 13, 'teens', 2, 'What does Job tell his friends would be their wisest action in Job 13:5?', 'Hold your peace and it would be your wisdom', 'Go and pray for three days in silence', 'Return home and let Job speak to God alone', 'Confess that they have spoken falsely', 'a', 'O that ye would altogether hold your peace! and it should be your wisdom (Job 13:5).'),
('Job', 13, 'teens', 3, 'What does Job warn his friends about speaking falsely for God in Job 13:7-10?', 'God will reprove them for accepting his person and speaking wickedly for him', 'Their families will suffer for their lies', 'They will lose all their possessions', 'They will never see the face of God', 'a', 'Will ye speak wickedly for God?...He will surely reprove you, if ye do secretly accept persons (Job 13:7, 10).'),
('Job', 13, 'teens', 4, 'What two things does Job ask God to withdraw in Job 13:21 so he can speak without terror?', 'God''s hand and God''s terror', 'God''s wrath and God''s silence', 'God''s judgement and God''s distance', 'God''s fire and God''s storm', 'a', 'Withdraw thine hand far from me: and let not thy dread make me afraid (Job 13:21).'),
('Job', 13, 'teens', 5, 'What does Job ask God in Job 13:23?', 'How many are mine iniquities and sins?', 'Why hast thou forsaken me in my suffering?', 'When will my suffering come to an end?', 'What must I do to be restored to health?', 'a', 'How many are mine iniquities and sins? make me to know my transgression and my sin (Job 13:23).'),
-- Adults
('Job', 13, 'adults', 1, 'How does Job describe his own observations in Job 13:1, distinguishing himself from his friends?', 'Lo, mine eye hath seen all this, mine ear hath heard and understood it', 'I have studied the scriptures more than any of you', 'I have spoken with the elders and learned from their counsel', 'My suffering has taught me what no book can give', 'a', 'Lo, mine eye hath seen all this, mine ear hath heard and understood it (Job 13:1).'),
('Job', 13, 'adults', 2, 'What metaphor does Job use for his friends'' counsel in Job 13:4?', 'Ye are forgers of lies, ye are all physicians of no value', 'Your words are like water poured on fire', 'You are clouds without rain', 'Your counsel is a broken reed', 'a', 'But ye are forgers of lies, ye are all physicians of no value (Job 13:4).'),
('Job', 13, 'adults', 3, 'What does Job warn will happen to his friends if they show partiality to God''s cause against him in Job 13:10?', 'He will surely reprove you, if ye do secretly accept persons', 'You will lose your place among the wise', 'Your prayers will not be heard', 'God will turn his face away from you', 'a', 'He will surely reprove you, if ye do secretly accept persons (Job 13:10).'),
('Job', 13, 'adults', 4, 'What two images does Job use for the fate of his friends'' defenses in Job 13:12?', 'Your remembrances are like unto ashes, your bodies to bodies of clay', 'Your arguments are like chaff and your wisdom like smoke', 'Your words are like the wind and your counsel like dust', 'Your confidence is as glass and your hope as morning dew', 'a', 'Your remembrances are like unto ashes, your bodies to bodies of clay (Job 13:12).'),
('Job', 13, 'adults', 5, 'What does Job mean when he says in Job 13:15 that he will "maintain mine own ways before him"?', 'He insists on presenting his case and defending his integrity before God even while trusting God', 'He plans to live according to his own rules from now on', 'He will not change his lifestyle regardless of God''s will', 'He will argue against God''s commands', 'a', 'Though he slay me, yet will I trust in him: but I will maintain mine own ways before him (Job 13:15) — Job trusts God yet insists on vindicating his integrity.'),
('Job', 13, 'adults', 6, 'What does Job identify as his basis for confidence that he shall be vindicated in Job 13:16?', 'He also shall be my salvation: for an hypocrite shall not come before him', 'His many years of righteous living', 'The testimony of the angels', 'His willingness to die for truth', 'a', 'He also shall be my salvation: for an hypocrite shall not come before him (Job 13:16).'),
('Job', 13, 'adults', 7, 'What does Job ask God to reveal to him in Job 13:23-24?', 'His iniquities and why God hides his face and counts him as an enemy', 'The number of his remaining days', 'The identity of the one who afflicted him', 'Whether his children are in God''s care', 'a', 'How many are mine iniquities and sins?...Wherefore hidest thou thy face, and holdest me for thine enemy? (Job 13:23-24).'),
('Job', 13, 'adults', 8, 'What theological significance does Job 13:15 ("Though he slay me, yet will I trust in him") carry in the history of faith?', 'It is one of Scripture''s greatest expressions of unconditional trust in God amid suffering, anticipating New Testament faith that endures through death', 'It proves that Job never truly doubted God', 'It shows that Job had lost hope in any earthly restoration', 'It is a statement of Job''s willingness to become a martyr', 'a', 'Job 13:15 is widely regarded as a pinnacle of Old Testament faith — trust that transcends even the threat of death itself.');

-- ═══ Job Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 14, 'kids', 1, 'How does Job describe the life of a man born of a woman in Job 14:1?', 'Few of days and full of trouble', 'Strong and full of hope', 'Short but filled with joy', 'Long but ending in sorrow', 'a', 'Man that is born of a woman is of few days, and full of trouble (Job 14:1).'),
('Job', 14, 'kids', 2, 'What does Job say about a tree that is cut down in Job 14:7?', 'There is hope for a tree; it will sprout again', 'A cut tree is gone forever', 'The tree''s roots hold all its life', 'The tree must be watered to survive', 'a', 'For there is hope of a tree, if it be cut down, that it will sprout again (Job 14:7).'),
('Job', 14, 'kids', 3, 'What great question does Job ask about death in Job 14:14?', 'If a man die, shall he live again?', 'Why do the righteous die young?', 'Will God remember the dead?', 'Where does the soul go after death?', 'a', 'If a man die, shall he live again? all the days of my appointed time will I wait (Job 14:14).'),
-- Teens
('Job', 14, 'teens', 1, 'To what two things does Job compare the brevity of human life in Job 14:2?', 'A flower that cometh forth and is cut down, and a shadow that fleeth', 'A candle that burns quickly and water that dries up', 'A morning cloud and the early dew that passes away', 'A river that runs fast and a wind that blows once', 'a', 'He cometh forth like a flower, and is cut down: he fleeth also as a shadow, and continueth not (Job 14:2).'),
('Job', 14, 'teens', 2, 'What limitation does Job ask God to set in Job 14:5-6?', 'That God would look away and let man enjoy his day like a hireling', 'That God would shorten the days of suffering', 'That God would grant one final prayer before death', 'That God would reveal his purpose to Job', 'a', 'Seeing his days are determined...turn from him, that he may rest, till he shall accomplish, as an hireling, his day (Job 14:5-6).'),
('Job', 14, 'teens', 3, 'How does Job contrast the fate of a man with that of a tree in Job 14:7-10?', 'A tree has hope of sprouting again, but a man giveth up the ghost and wasteth away', 'A tree provides shade but a man seeks shelter', 'A tree grows taller each year but a man grows weaker', 'A tree is rooted in earth but a man walks above it', 'a', 'There is hope of a tree...but man dieth, and wasteth away: yea, man giveth up the ghost, and where is he? (Job 14:7, 10).'),
('Job', 14, 'teens', 4, 'What does Job say about rivers and floods in connection with death in Job 14:11?', 'As the waters fail from the sea, and the flood decayeth and drieth up: so man lieth down, and riseth not', 'The flood comes and goes but man endures forever', 'The river flows to the sea but man returns to the dust', 'Waters rise and fall but God''s word remains', 'a', 'As the waters fail from the sea, and the flood decayeth and drieth up: So man lieth down, and riseth not (Job 14:11).'),
('Job', 14, 'teens', 5, 'What does Job hope God will do for him if he waits through his appointed time in Job 14:15?', 'God will call and Job will answer, and God will have a desire to the work of his hands', 'God will restore his health and rebuild his house', 'God will send an angel with a message of comfort', 'God will reveal the reason for all his suffering', 'a', 'Thou shalt call, and I will answer thee: thou wilt have a desire to the work of thine hands (Job 14:15).'),
-- Adults
('Job', 14, 'adults', 1, 'What does Job say about the cleanness of the unclean in Job 14:4?', 'Who can bring a clean thing out of an unclean? not one', 'The unclean can be made clean by water and sacrifice', 'Only God can make the sinful pure', 'No man is born without the stain of sin', 'a', 'Who can bring a clean thing out of an unclean? not one (Job 14:4).'),
('Job', 14, 'adults', 2, 'What specific limits does Job say God has set for man in Job 14:5?', 'His days are determined, the number of his months are with thee, thou hast appointed his bounds that he cannot pass', 'God has set the length of a man''s suffering', 'God has numbered a man''s words before he speaks', 'God has appointed when each man shall repent', 'a', 'Seeing his days are determined, the number of his months are with thee, thou hast appointed his bounds that he cannot pass (Job 14:5).'),
('Job', 14, 'adults', 3, 'How does Job describe the revival of a tree cut down in Job 14:7-9?', 'Through the scent of water it will bud and bring forth boughs like a plant', 'The tree''s roots send up new life in spring', 'Its stump remains green beneath the snow', 'New shoots spring forth from seeds it dropped', 'a', 'Though the root thereof wax old in the earth...yet through the scent of water it will bud, and bring forth boughs like a plant (Job 14:8-9).'),
('Job', 14, 'adults', 4, 'What does Job say about the permanence of a man''s absence in death in Job 14:12?', 'Man lieth down and riseth not: till the heavens be no more, they shall not awake, nor be raised out of their sleep', 'A man''s soul lingers near his grave for many days', 'The dead return to dust and are forgotten', 'Death takes man but God can restore', 'a', 'Man lieth down, and riseth not: till the heavens be no more, they shall not awake, nor be raised out of their sleep (Job 14:12).'),
('Job', 14, 'adults', 5, 'What does Job ask God to do in Job 14:13 regarding Sheol?', 'That God would hide him in Sheol, keep him secret, and appoint him a set time and remember him', 'That God would allow him to speak to the dead', 'That God would bring him quickly to Sheol to end his pain', 'That God would reveal what happens in Sheol', 'a', 'O that thou wouldest hide me in the grave, that thou wouldest keep me secret...that thou wouldest appoint me a set time, and remember me! (Job 14:13).'),
('Job', 14, 'adults', 6, 'What does Job say God seals up in Job 14:17 as part of his judgment?', 'My transgression is sealed up in a bag, and thou sewest up mine iniquity', 'My prayers are sealed before the throne', 'My days are counted and stored up in heaven', 'My words are recorded and cannot be erased', 'a', 'My transgression is sealed up in a bag, and thou sewest up mine iniquity (Job 14:17).'),
('Job', 14, 'adults', 7, 'How does Job describe the erosion of human hope in Job 14:18-19?', 'As mountains fall and rocks are moved, and waters wear stones and washings wash away the dust of the earth, so thou destroyest the hope of man', 'Hope fades like morning mist when trouble comes', 'The hope of man is like a fragile vessel', 'Man''s hope is eaten away by his own doubts', 'a', 'The mountain falling cometh to nought...The waters wear the stones...so thou destroyest the hope of man (Job 14:18-19).'),
('Job', 14, 'adults', 8, 'How does Job 14:14''s question "If a man die, shall he live again?" function within the larger argument of the book?', 'It is the first great resurrection question in the OT poetic books, expressing hope for vindication beyond death even as Job doubts its possibility in this life', 'It proves Job did not believe in any afterlife', 'It is a rhetorical device to blame God for not revealing the afterlife', 'It anticipates only the physical restoration Job later receives', 'a', 'Job 14:14 is a pivotal OT resurrection question; Job expresses guarded hope: "all the days of my appointed time will I wait, till my change come" (Job 14:14).');

-- ═══ Job Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 15, 'kids', 1, 'Who speaks in Job chapter 15?', 'Eliphaz the Temanite', 'Bildad the Shuhite', 'Zophar the Naamathite', 'Elihu the Buzite', 'a', 'Then answered Eliphaz the Temanite (Job 15:1) — this is Eliphaz''s second speech.'),
('Job', 15, 'kids', 2, 'What does Eliphaz say Job''s own mouth does in Job 15:6?', 'Thine own mouth condemneth thee', 'Your words prove your righteousness', 'Your lips speak only truth', 'Your prayers go unanswered', 'a', 'Thine own mouth condemneth thee, and not I: yea, thine own lips testify against thee (Job 15:6).'),
('Job', 15, 'kids', 3, 'What does Eliphaz say the wicked man is filled with in Job 15:20?', 'The wicked man travaileth with pain all his days', 'Great riches but no peace', 'Fear of God and trembling', 'The wisdom of his fathers', 'a', 'The wicked man travaileth with pain all his days, and the number of years is hidden to the oppressor (Job 15:20).'),
-- Teens
('Job', 15, 'teens', 1, 'What rhetorical question does Eliphaz ask Job in Job 15:7-8?', 'Art thou the first man that was born? or wast thou made before the hills? Hast thou heard the secret of God?', 'Were you present at creation and do you know the depths of wisdom?', 'Have you counted the stars and measured the deep?', 'Did God speak to you in a dream or a vision?', 'a', 'Art thou the first man that was born? or wast thou made before the hills? Hast thou heard the secret of God? (Job 15:7-8).'),
('Job', 15, 'teens', 2, 'What does Eliphaz say Job is doing to fear and religion in Job 15:4?', 'Thou castest off fear, and restrainest prayer before God', 'You are teaching others to doubt God', 'You are making the young men rebellious', 'You are using prayer as a weapon against God', 'a', 'Yea, thou castest off fear, and restrainest prayer before God (Job 15:4).'),
('Job', 15, 'teens', 3, 'What does Eliphaz say about the purity of the heavens and angels in Job 15:15?', 'He putteth no trust in his saints; yea, the heavens are not clean in his sight', 'The angels sing of his holiness forever', 'The heavens declare his righteousness', 'His servants minister before him in perfect holiness', 'a', 'Behold, he putteth no trust in his saints; yea, the heavens are not clean in his sight (Job 15:15).'),
('Job', 15, 'teens', 4, 'How does Eliphaz describe what the wicked man hears in Job 15:21?', 'A dreadful sound is in his ears; in prosperity the destroyer shall come upon him', 'The voice of God calling him to repent', 'The cries of those he has wronged', 'Thunder and storms pursuing him', 'a', 'A dreadful sound is in his ears: in prosperity the destroyer shall come upon him (Job 15:21).'),
('Job', 15, 'teens', 5, 'What does Eliphaz say about the wicked man''s dwelling in Job 15:28?', 'He dwelleth in desolate cities, in houses no man inhabiteth', 'His house is built on sand and falls in the storm', 'The wicked man''s tent is torn from its pegs', 'His home becomes a dwelling for wild beasts', 'a', 'And he dwelleth in desolate cities, and in houses which no man inhabiteth, which are ready to become heaps (Job 15:28).'),
-- Adults
('Job', 15, 'adults', 1, 'How does Eliphaz characterize Job''s speech in Job 15:2-3?', 'Should a wise man utter vain knowledge and fill his belly with the east wind, and reason with unprofitable talk?', 'Job''s words are foolish because he speaks without suffering', 'Your speech brings dishonor upon your family', 'A wise man does not defend himself before God', 'a', 'Should a wise man utter vain knowledge, and fill his belly with the east wind?...with speeches wherewith he can do no good? (Job 15:2-3).'),
('Job', 15, 'adults', 2, 'What claim about exclusive wisdom does Eliphaz challenge in Job 15:9-10?', 'What knowest thou that we know not? with us are both the grayheaded and very aged men, much elder than thy father', 'You speak as though God has given you alone his counsel', 'Your wisdom came from foreign lands, not from our traditions', 'Job thinks his affliction has made him wiser than any living man', 'a', 'What knowest thou, that we know not?...with us are both the grayheaded and very aged men, much elder than thy father (Job 15:9-10).'),
('Job', 15, 'adults', 3, 'What does Eliphaz say about man''s condition in Job 15:14?', 'What is man, that he should be clean? and he which is born of a woman, that he should be righteous?', 'Man cannot argue with God no matter how righteous he appears', 'Man born of dust can never approach the holy God', 'No flesh can stand before the judgment of the Almighty', 'a', 'What is man, that he should be clean? and he which is born of a woman, that he should be righteous? (Job 15:14).'),
('Job', 15, 'adults', 4, 'How does Eliphaz describe man''s moral condition in Job 15:16?', 'How much more abominable and filthy is man, which drinketh iniquity like water', 'Man is born corrupt and can do no good of himself', 'Every thought of man''s heart is evil from his youth', 'Man''s sin is as deep as the sea and as high as the heavens', 'a', 'How much more abominable and filthy is man, which drinketh iniquity like water? (Job 15:16).'),
('Job', 15, 'adults', 5, 'What does Eliphaz say about the wicked man''s wealth in Job 15:29?', 'He shall not be rich, neither shall his substance continue, neither shall he prolong the perfection thereof upon the earth', 'The wicked man gathers wealth but it is stolen from him', 'Riches gained by wickedness vanish in a single night', 'The wicked man''s gold turns to dust in his hands', 'a', 'He shall not be rich, neither shall his substance continue, neither shall he prolong the perfection thereof upon the earth (Job 15:29).'),
('Job', 15, 'adults', 6, 'What agricultural image does Eliphaz use to describe the wicked in Job 15:30-33?', 'He shall not depart out of darkness; his branch shall not be green; and he shall cast off his flower as the vine, and as the olive', 'The wicked man is like a weed among wheat', 'Like a vine without water that withers before harvest', 'The wicked man''s tree is struck by lightning', 'a', 'He shall not depart out of darkness...his branch shall not be green...he shall cast off his flower as the vine (Job 15:30, 32-33).'),
('Job', 15, 'adults', 7, 'What does Eliphaz say the wicked man''s congregation shall be in Job 15:34?', 'The congregation of hypocrites shall be desolate, and fire shall consume the tabernacles of bribery', 'The assembly of the wicked shall scatter before the righteous', 'Those who gather with the wicked shall perish with them', 'The wicked man''s followers shall be put to shame', 'a', 'For the congregation of hypocrites shall be desolate, and fire shall consume the tabernacles of bribery (Job 15:34).'),
('Job', 15, 'adults', 8, 'What is the theological weakness in Eliphaz''s second speech in chapter 15 compared to his first speech in chapter 4?', 'He has moved from gentle rebuke to personal attack, accusing Job of undermining religion and filling himself with wind, without evidence beyond Job''s protest of innocence', 'He no longer believes in God''s mercy', 'He has abandoned the doctrine of repentance', 'He blames Job''s children for their father''s trouble', 'a', 'Eliphaz''s second speech is harsher — he accuses Job of casting off fear and restraining prayer (Job 15:4) with no new evidence, revealing his argument has hardened into personal attack.');

-- ═══ Job Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 16, 'kids', 1, 'What did Job call his three friends in Job 16:2?', 'Miserable comforters', 'Faithful companions', 'Wise counsellors', 'Unkind strangers', 'a', 'Job said, "I have heard many such things: miserable comforters are ye all" (Job 16:2).'),
('Job', 16, 'kids', 2, 'Where does Job say his witness is in Job 16:19?', 'In heaven', 'In the temple', 'In his heart', 'Among the angels', 'a', 'Also now, behold, my witness is in heaven, and my record is on high (Job 16:19).'),
('Job', 16, 'kids', 3, 'What does Job say his eyes do because of his suffering in Job 16:20?', 'Mine eye poureth out tears unto God', 'My eyes grow dim with grief', 'I cannot see through my tears', 'My eyes close and will not open', 'a', 'My friends scorn me: but mine eye poureth out tears unto God (Job 16:20).'),
-- Teens
('Job', 16, 'teens', 1, 'What does Job say he would do if his friends were in his place in Job 16:4-5?', 'I could heap up words against you, but I would strengthen you with my mouth and comfort you', 'I would sit silently and weep with you', 'I would offer a sacrifice on your behalf', 'I would not accuse you as you have accused me', 'a', 'I could heap up words against you, and shake mine head at you. But I would strengthen you with my mouth (Job 16:4-5).'),
('Job', 16, 'teens', 2, 'How does Job describe God''s attack on him in Job 16:9?', 'He teareth me in his wrath, who hateth me: he gnasheth upon me with his teeth', 'God has forsaken me and left me without shelter', 'God sends his arrows against me without cause', 'God has sealed my mouth so I cannot speak', 'a', 'He teareth me in his wrath, who hateth me: he gnasheth upon me with his teeth; mine enemy sharpeneth his eyes upon me (Job 16:9).'),
('Job', 16, 'teens', 3, 'What physical sufferings does Job describe in Job 16:15-16?', 'He has sewed sackcloth on his skin, defiled his horn in the dust, his face is foul with weeping', 'Covered in wounds from head to foot with no comfort', 'His bones ache and his flesh wastes away before God', 'He is unable to eat or drink and grows weaker each day', 'a', 'I have sewed sackcloth upon my skin, and defiled my horn in the dust. My face is foul with weeping (Job 16:15-16).'),
('Job', 16, 'teens', 4, 'What does Job say about the purity of his prayer in Job 16:17?', 'Not for any injustice in mine hands: also my prayer is pure', 'Though I suffer, I have not sinned against the poor', 'My hands are clean even if my body is broken', 'God knows I never lifted my hand against the innocent', 'a', 'Not for any injustice in mine hands: also my prayer is pure (Job 16:17).'),
('Job', 16, 'teens', 5, 'What does Job ask the earth not to do in Job 16:18?', 'Cover not thou my blood, and let my cry have no place', 'Let not the dust receive my bones before I am vindicated', 'Do not swallow me as thou hast swallowed others', 'Receive not my tears as if they were the waters of the sea', 'a', 'O earth, cover not thou my blood, and let my cry have no place (Job 16:18).'),
-- Adults
('Job', 16, 'adults', 1, 'What question does Job pose to his friends in Job 16:3 about their speeches?', 'Shall vain words have an end? or what emboldeneth thee that thou answerest?', 'How long will you torment me with your words?', 'Do you think God is pleased with your defence of him?', 'Will you speak falsely for God and think you do him honour?', 'a', 'Shall vain words have an end? or what emboldeneth thee that thou answerest? (Job 16:3).'),
('Job', 16, 'adults', 2, 'How does Job describe God handing him over to the ungodly in Job 16:11?', 'God hath delivered me to the ungodly, and turned me over into the hands of the wicked', 'God has allowed my enemies to surround my tent', 'The Almighty has sent my adversaries against me', 'My tormentors were appointed by the heavenly council', 'a', 'God hath delivered me to the ungodly, and turned me over into the hands of the wicked (Job 16:11).'),
('Job', 16, 'adults', 3, 'What military imagery does Job use to describe God''s attack in Job 16:12-14?', 'He hath set me up for his mark, his archers surround me, he breaketh me with breach upon breach like a mighty man', 'God has laid siege to my city and broken down my walls', 'God''s sword has pierced me through and through', 'Like a great flood God''s judgment overwhelms me', 'a', 'He hath set me up for his mark...His archers compass me round about...he breaketh me with breach upon breach, he runneth upon me like a giant (Job 16:12-14).'),
('Job', 16, 'adults', 4, 'What does Job call his advocate in heaven in Job 16:19-21?', 'My witness in heaven and my record on high who shall plead for a man with God as a man pleadeth for his neighbour', 'The holy one who sits at God''s right hand', 'An angel of mercy appointed to my cause', 'The spirit of my righteousness before the throne', 'a', 'My witness is in heaven...my record is on high...Also my friends scorn me...O that one might plead for a man with God, as a man pleadeth for his neighbour (Job 16:19-21).'),
('Job', 16, 'adults', 5, 'What does Job say about his spirit in Job 16:22?', 'When a few years are come, then I shall go the way whence I shall not return', 'My spirit grows weaker with each passing day', 'The spirit God gave me will outlast my suffering', 'I will not yield up my spirit until I am vindicated', 'a', 'When a few years are come, then I shall go the way whence I shall not return (Job 16:22).'),
('Job', 16, 'adults', 6, 'What does the concept of a heavenly witness/advocate in Job 16:19-21 anticipate theologically?', 'It prefigures the intercessory work of Christ as the mediator between God and man', 'It establishes the Jewish doctrine of guardian angels', 'It proves that the dead can hear the prayers of the living', 'It introduces the idea that all righteous men become advocates after death', 'a', 'Job''s cry for a heavenly witness who would plead his cause (Job 16:19-21) anticipates the NT teaching of Christ as mediator and advocate (1 Timothy 2:5; 1 John 2:1).'),
('Job', 16, 'adults', 7, 'What is the significance of Job asking the earth not to cover his blood in Job 16:18?', 'Uncovered blood cried out for justice in ancient Near Eastern thought (cf. Genesis 4:10), so Job wants his innocent suffering to remain as a testimony before God demanding vindication', 'Job feared his death would be forgotten by his descendants', 'He wanted his grave to remain visible as a monument', 'Blood on the ground was considered a curse in Israelite culture', 'a', 'O earth, cover not thou my blood (Job 16:18) — as Abel''s blood cried from the ground, Job wants his innocent suffering to cry out before God (cf. Genesis 4:10).'),
('Job', 16, 'adults', 8, 'How does Job''s self-description as one whose face is foul with weeping (Job 16:16) connect to his claim of pure prayer in Job 16:17?', 'The contrast shows Job''s outward agony is matched by inward integrity — his weeping is not guilt but grief, and his prayer is uncorrupted by injustice', 'Job weeps in repentance even as he protests his innocence', 'His tears demonstrate that he has no anger toward God', 'The foul face is a sign of his complete humility before the Almighty', 'a', 'My face is foul with weeping...not for any injustice in mine hands: also my prayer is pure (Job 16:16-17) — outward distress and inward purity stand together in Job''s testimony.');

-- ═══ Job Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 17, 'kids', 1, 'What does Job say about his days in Job 17:1?', 'My days are past', 'My days are numbered by God', 'My days are full of sorrow', 'My days will be restored', 'a', 'My breath is corrupt, my days are extinct, the graves are ready for me (Job 17:1).'),
('Job', 17, 'kids', 2, 'Who does Job say has made him a byword in Job 17:6?', 'God hath made me a byword of the people', 'His enemies in the marketplace', 'The rulers of his city', 'His own children', 'a', 'He hath made me also a byword of the people; and aforetime I was as a tabret (Job 17:6).'),
('Job', 17, 'kids', 3, 'Where does Job say his hope has gone in Job 17:15?', 'Where is now my hope?', 'My hope was carried away by the wind', 'Hope has been taken by my enemies', 'My hope is hidden in the grave', 'a', 'And where is now my hope? as for my hope, who shall see it? (Job 17:15).'),
-- Teens
('Job', 17, 'teens', 1, 'What does Job ask God to do in Job 17:3 regarding his pledge?', 'Lay down now, put me in a surety with thee; who is he that will strike hands with me?', 'Give me one more day to present my case', 'Send me a messenger from heaven', 'Record my words before I die', 'a', 'Lay down now, put me in a surety with thee; who is he that will strike hands with me? (Job 17:3).'),
('Job', 17, 'teens', 2, 'What does Job observe about the fate of the upright in Job 17:8-9?', 'The upright man is astonished, the innocent stirs up against the hypocrite, and the righteous holdeth on his way and gains strength', 'The upright man is rewarded swiftly by God', 'The righteous man is protected from all suffering', 'God reveals his purposes to the upright in every generation', 'a', 'Upright men shall be astonied at this...the innocent shall stir up himself against the hypocrite. The righteous also shall hold on his way, and he that hath clean hands shall be stronger and stronger (Job 17:8-9).'),
('Job', 17, 'teens', 3, 'What does Job say about the wisdom of his friends in Job 17:10?', 'Return, and come now: for I cannot find one wise man among you', 'Your counsel is empty and your comfort false', 'You speak as men who have never known affliction', 'Your wisdom ends where my suffering begins', 'a', 'But as for you all, do ye return, and come now: for I cannot find one wise man among you (Job 17:10).'),
('Job', 17, 'teens', 4, 'What does Job say about his plans and the thoughts of his heart in Job 17:11?', 'My days are past, my purposes are broken off, even the thoughts of my heart', 'My plans were great but God has shattered them', 'Every purpose I formed has turned to grief', 'My thoughts are only of death and the grave', 'a', 'My days are past, my purposes are broken off, even the thoughts of my heart (Job 17:11).'),
('Job', 17, 'teens', 5, 'What does Job say about the location of his rest and hope in Job 17:13-16?', 'If I wait, the grave is mine house; my hope shall go down to the bars of the pit, and rest together in the dust', 'He will wait for God in the depths of his grief', 'His rest comes only when the suffering ends', 'Hope will return when the morning comes', 'a', 'If I wait, the grave is mine house: I have made my bed in the darkness...They shall go down to the bars of the pit, when our rest together is in the dust (Job 17:13, 16).'),
-- Adults
('Job', 17, 'adults', 1, 'What physical description does Job give of his condition in Job 17:1?', 'My breath is corrupt, my days are extinct, the graves are ready for me', 'My body is consumed by worms and my strength is dried up', 'My skin is broken and my flesh cleaves to my bones', 'My eyes are blind and my ears no longer hear', 'a', 'My breath is corrupt, my days are extinct, the graves are ready for me (Job 17:1).'),
('Job', 17, 'adults', 2, 'What does Job say about God''s action toward his friends'' understanding in Job 17:4?', 'Thou hast hid their heart from understanding: therefore shalt thou not exalt them', 'God has allowed them to be deceived by their own wisdom', 'Their hearts are hardened because they have not suffered', 'God will judge them for their false comfort', 'a', 'For thou hast hid their heart from understanding: therefore shalt thou not exalt them (Job 17:4).'),
('Job', 17, 'adults', 3, 'What physical deterioration does Job describe in Job 17:7?', 'Mine eye also is dim by reason of sorrow, and all my members are as a shadow', 'My limbs fail me and my flesh rots before my eyes', 'My hands are too weak to lift and my feet refuse to walk', 'My face is pale and my skin hangs from my bones', 'a', 'Mine eye also is dim by reason of sorrow, and all my members are as a shadow (Job 17:7).'),
('Job', 17, 'adults', 4, 'How does Job describe the changing of night and day by his friends in Job 17:12?', 'They change the night into day: the light is short because of darkness', 'They call my darkness light and my sorrow joy', 'They see only sunshine while I live in shadow', 'My friends count the days of my suffering as days of blessing', 'a', 'They change the night into day: the light is short because of darkness (Job 17:12).'),
('Job', 17, 'adults', 5, 'What is the significance of Job saying "the righteous shall hold on his way" in Job 17:9?', 'Even surrounded by accusation and despair, Job affirms that the person with clean hands grows stronger — a declaration of persevering faith', 'He is predicting his own recovery', 'He teaches that only perfect people can face God', 'He is arguing that the righteous never suffer', 'a', 'The righteous also shall hold on his way, and he that hath clean hands shall be stronger and stronger (Job 17:9) — faith perseveres even in the pit.'),
('Job', 17, 'adults', 6, 'What does Job say to his friends about their attempts to renew their arguments in Job 17:10?', 'But as for you all, do ye return, and come now: for I cannot find one wise man among you', 'I have heard enough — your counsel only deepens my wounds', 'Speak no more to me of God''s justice, for you do not understand it', 'Your words are as empty as the wind that passes over the desert', 'a', 'But as for you all, do ye return, and come now: for I cannot find one wise man among you (Job 17:10).'),
('Job', 17, 'adults', 7, 'How does Job describe the corruption of the human community around him in Job 17:5?', 'He that speaketh flattery to his friends, even the eyes of his children shall fail', 'My companions have turned against me to gain favour with the powerful', 'Those who mocked me will themselves be mocked', 'My name has been defamed among those who once called me friend', 'a', 'He that speaketh flattery to his friends, even the eyes of his children shall fail (Job 17:5).'),
('Job', 17, 'adults', 8, 'What is the theological purpose of chapter 17 in the structure of Job''s speeches?', 'It represents the nadir of Job''s despair — his hope seems extinguished and the grave appears to be his only destination, yet he still addresses God directly, showing faith survives even the darkest night', 'It marks Job''s final rejection of God''s sovereignty', 'It proves that Job has abandoned belief in an afterlife', 'It sets up Elihu''s entrance by showing that the three friends have completely failed', 'a', 'Chapter 17 is Job''s darkest soliloquy; hope seems buried with him (Job 17:15-16), yet his direct address to God throughout shows that even in despair he has not abandoned relationship with God.');

-- ═══ Job Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 18, 'kids', 1, 'Who speaks in Job chapter 18?', 'Bildad the Shuhite', 'Eliphaz the Temanite', 'Zophar the Naamathite', 'Elihu the Buzite', 'a', 'Then answered Bildad the Shuhite (Job 18:1) — this is Bildad''s second speech.'),
('Job', 18, 'kids', 2, 'What does Bildad say happens to the light of the wicked in Job 18:5?', 'The light of the wicked shall be put out', 'The wicked man''s light burns fiercely for a time', 'His lamp goes dark only when he repents', 'The flame of the wicked lights up the whole earth', 'a', 'Yea, the light of the wicked shall be put out, and the spark of his fire shall not shine (Job 18:5).'),
('Job', 18, 'kids', 3, 'What does Bildad say will happen to the wicked man''s name in Job 18:17?', 'His remembrance shall perish from the earth', 'His name will be remembered as a warning', 'His children will carry his name forever', 'His name will be written in the book of the wicked', 'a', 'His remembrance shall perish from the earth, and he shall have no name in the street (Job 18:17).'),
-- Teens
('Job', 18, 'teens', 1, 'What does Bildad accuse Job of in Job 18:3?', 'Wherefore are we counted as beasts, and reputed vile in your sight?', 'Speaking blasphemy before the congregation', 'Refusing to listen to the wisdom of the aged', 'Turning his face away from God in bitterness', 'a', 'Wherefore are we counted as beasts, and reputed vile in your sight? (Job 18:3).'),
('Job', 18, 'teens', 2, 'What trap images does Bildad use to describe the fate of the wicked in Job 18:8-10?', 'He is cast into a net by his own feet; he walks on a snare; a trap, a robber, and a snare are laid for him', 'The wicked man falls into a pit of his own digging', 'His enemies set an ambush on his road', 'The wicked man is caught by the web of his own lies', 'a', 'For he is cast into a net by his own feet...The gin shall take him by the heel, the robber shall prevail against him. The snare is laid...and a trap for him in the way (Job 18:8-10).'),
('Job', 18, 'teens', 3, 'What does Bildad say devours the wicked man''s skin in Job 18:13?', 'It shall devour the strength of his skin: even the firstborn of death shall devour his strength', 'Worms shall eat away his flesh in the grave', 'Disease shall spread from his body to all around him', 'His own sin consumes him from within', 'a', 'It shall devour the strength of his skin: even the firstborn of death shall devour his strength (Job 18:13).'),
('Job', 18, 'teens', 4, 'Where does Bildad say the wicked man is driven in Job 18:14?', 'He is rooted out of his tabernacle and brought to the king of terrors', 'The wicked man flees from city to city but finds no rest', 'He is thrown into the outer darkness forever', 'God drives him from the land of the living', 'a', 'His confidence shall be rooted out of his tabernacle, and it shall bring him to the king of terrors (Job 18:14).'),
('Job', 18, 'teens', 5, 'What agricultural image does Bildad use for the wickedness of the wicked man''s family in Job 18:16?', 'His roots shall be dried up beneath, and above shall his branch be cut off', 'His vine produces bitter fruit and withers in drought', 'His seed falls on rocky ground and bears nothing', 'The harvest of his house is taken by strangers', 'a', 'His roots shall be dried up beneath, and above shall his branch be cut off (Job 18:16).'),
-- Adults
('Job', 18, 'adults', 1, 'What rhetorical question does Bildad use to rebuke Job in Job 18:4?', 'He that teareth himself in his anger: shall the earth be forsaken for thee? and shall the rock be removed out of his place?', 'Do you think God changes his laws to suit your complaint?', 'Is the Almighty to be moved by the tears of one suffering man?', 'Shall wisdom perish because you refuse to hear it?', 'a', 'He that teareth himself in his anger: shall the earth be forsaken for thee? and shall the rock be removed out of his place? (Job 18:4).'),
('Job', 18, 'adults', 2, 'How does Bildad describe the dwelling of the wicked in Job 18:6?', 'The light shall be dark in his tabernacle, and his candle shall be put out with him', 'Shadows fill his house and terror guards his threshold', 'The wicked man''s home crumbles around him', 'Darkness spreads from his door to all his possessions', 'a', 'The light shall be dark in his tabernacle, and his candle shall be put out with him (Job 18:6).'),
('Job', 18, 'adults', 3, 'What does Bildad say about the wicked man''s own counsel in Job 18:7?', 'The steps of his strength shall be straitened, and his own counsel shall cast him down', 'The wicked man''s plans turn against him at every step', 'His wisdom fails at the moment he needs it most', 'The advice he gives to others destroys him in the end', 'a', 'The steps of his strength shall be straitened, and his own counsel shall cast him down (Job 18:7).'),
('Job', 18, 'adults', 4, 'What does the phrase "the firstborn of death" in Job 18:13 mean in context?', 'The most deadly and dreadful disease, which devours the wicked man''s strength', 'The firstborn son of the wicked will die first', 'Death''s firstborn is the angel of destruction', 'The first act of God''s judgment upon the wicked', 'a', 'It shall devour the strength of his skin: even the firstborn of death shall devour his strength (Job 18:13) — referring to a most deadly, consuming disease.'),
('Job', 18, 'adults', 5, 'What does Bildad say dwells in the wicked man''s tent in Job 18:15?', 'It shall dwell in his tabernacle, because it is none of his: brimstone shall be scattered upon his habitation', 'Fear and desolation settle in his home', 'His enemies take possession of all he owned', 'Darkness and mourning fill every room', 'a', 'It shall dwell in his tabernacle, because it is none of his: brimstone shall be scattered upon his habitation (Job 18:15).'),
('Job', 18, 'adults', 6, 'What does Bildad say about the fate of the wicked man''s posterity and survivors in Job 18:19?', 'He shall neither have son nor nephew among his people, nor any remaining in his dwellings', 'His children will bear his shame for three generations', 'His descendants will wander homeless among the nations', 'No one will build on the ruins of his house', 'a', 'He shall neither have son nor nephew among his people, nor any remaining in his dwellings (Job 18:19).'),
('Job', 18, 'adults', 7, 'What reaction do the generations of east and west have to the fate of the wicked in Job 18:20?', 'They that come after him shall be astonied at his day, as they that went before were affrighted', 'The nations marvel at how swiftly the wicked are destroyed', 'All the earth trembles when God punishes the great sinner', 'Distant peoples laugh at the fall of the oppressor', 'a', 'They that come after him shall be astonied at his day, as they that went before were affrighted (Job 18:20).'),
('Job', 18, 'adults', 8, 'What is the rhetorical effect of Bildad''s extended catalogue of disaster in Job 18:5-21, and how does it relate to Job?', 'Bildad constructs a detailed picture of the wicked man''s fate to imply without naming it that Job''s suffering fits this pattern exactly, making his argument a sustained insinuation of guilt', 'Bildad is giving a general sermon about divine justice with no specific reference to Job', 'Bildad is defending God''s goodness against Job''s charges of injustice', 'Bildad is warning others present not to sin as Job has sinned', 'a', 'Bildad never names Job directly but builds his catalogue (Job 18:5-20) so that every detail mirrors Job''s condition — light put out, driven from his tent, name forgotten — making the chapter a thinly veiled accusation.');

-- ═══ Job Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 19, 'kids', 1, 'What great statement of faith did Job make in Job 19:25?', 'I know that my redeemer liveth', 'God will never leave me alone', 'The Lord is my shepherd and helper', 'Though I walk through darkness I fear no evil', 'a', 'For I know that my redeemer liveth, and that he shall stand at the latter day upon the earth (Job 19:25).'),
('Job', 19, 'kids', 2, 'What does Job ask his friends in Job 19:21?', 'Have pity upon me, for the hand of God hath touched me', 'Why will you not comfort me in my trouble?', 'Do you not see how greatly I suffer?', 'Please stop speaking against me', 'a', 'Have pity upon me, have pity upon me, O ye my friends; for the hand of God hath touched me (Job 19:21).'),
('Job', 19, 'kids', 3, 'What does Job say he will see after his skin has been destroyed in Job 19:26?', 'Yet in my flesh shall I see God', 'I will rise and behold my redeemer', 'My eyes will see the glory of heaven', 'I will look upon the face of the Lord', 'a', 'And though after my skin worms destroy this body, yet in my flesh shall I see God (Job 19:26).'),
-- Teens
('Job', 19, 'teens', 1, 'What does Job say God has done to him in Job 19:6?', 'God hath overthrown me, and hath compassed me with his net', 'God has taken away all my blessings', 'God has set my enemies against me like an army', 'God has removed his presence far from me', 'a', 'Know now that God hath overthrown me, and hath compassed me with his net (Job 19:6).'),
('Job', 19, 'teens', 2, 'How does Job describe his social isolation in Job 19:13-14?', 'He hath put my brethren far from me, and mine acquaintance are verily estranged from me; my kinsfolk have failed', 'My friends left because of my disease', 'The men of my city drove me from the gate', 'My enemies spread lies about me until I was alone', 'a', 'He hath put my brethren far from me, and mine acquaintance are verily estranged from me. My kinsfolk have failed (Job 19:13-14).'),
('Job', 19, 'teens', 3, 'Who does Job say has become strange to him in Job 19:15-17?', 'They that dwell in mine house, my maids, and my own wife', 'His former servants and business partners', 'The leaders of the city and his allies', 'His teachers and the men of his youth', 'a', 'They that dwell in mine house, and my maids, count me for a stranger...My breath is strange to my wife (Job 19:15-17).'),
('Job', 19, 'teens', 4, 'What does Job say about children''s contempt for him in Job 19:18?', 'Yea, young children despised me; I arose and they spake against me', 'Even the smallest boys mock me in the street', 'Children who knew me before now refuse to greet me', 'The sons of the wicked have become my tormentors', 'a', 'Yea, young children despised me; I arose, and they spake against me (Job 19:18).'),
('Job', 19, 'teens', 5, 'What does Job say about seeing God on his side in Job 19:27?', 'Whom I shall see for myself, and mine eyes shall behold, and not another; though my reins be consumed within me', 'God himself will rise and declare my innocence', 'I will see my redeemer standing beside me', 'My eyes will behold the salvation God has planned', 'a', 'Whom I shall see for myself, and mine eyes shall behold, and not another; though my reins be consumed within me (Job 19:27).'),
-- Adults
('Job', 19, 'adults', 1, 'How many times does Job say his friends have wronged and broken him with words in Job 19:2-3?', 'Ten times have ye reproached me; ye are not ashamed that ye make yourselves strange to me', 'Seven times have they wounded me with their counsel', 'More than I can count have I heard your reproaches', 'Three times have ye come against me without mercy', 'a', 'How long will ye vex my soul, and break me in pieces with words? These ten times have ye reproached me (Job 19:2-3).'),
('Job', 19, 'adults', 2, 'What does Job say about God''s seeming indifference to his cry in Job 19:7?', 'Behold, I cry out of wrong, but I am not heard: I cry aloud, but there is no judgment', 'God has turned his ear away from my prayers', 'My supplications rise but find no favour', 'The heavens are shut against me', 'a', 'Behold, I cry out of wrong, but I am not heard: I cry aloud, but there is no judgment (Job 19:7).'),
('Job', 19, 'adults', 3, 'What does Job say God has done to his path and darkness in Job 19:8?', 'He hath fenced up my way that I cannot pass, and he hath set darkness in my paths', 'God has removed the light from before me and blocked my way', 'The Almighty has shut my mouth and stopped my steps', 'God has drawn a line I cannot cross', 'a', 'He hath fenced up my way that I cannot pass, and he hath set darkness in my paths (Job 19:8).'),
('Job', 19, 'adults', 4, 'How does Job describe the stripping away of his honour and hope in Job 19:9-10?', 'He hath stripped me of my glory and taken the crown from my head. He hath destroyed me on every side, and I am gone; and mine hope hath he removed like a tree', 'God has taken away my wealth and left me destitute', 'My honour lies in the dust and my enemies tread upon it', 'God has silenced my voice and made my name a reproach', 'a', 'He hath stripped me of my glory, and taken the crown from my head. He hath destroyed me on every side...and mine hope hath he removed like a tree (Job 19:9-10).'),
('Job', 19, 'adults', 5, 'What is the full three-part confession of faith that Job makes in Job 19:25-27?', 'I know my redeemer liveth and shall stand on the earth at the latter day; after worms destroy this body yet in my flesh I shall see God; I shall see him for myself and not another', 'God is alive, God will come, and God will vindicate the innocent', 'My redeemer is holy, my redeemer is near, and my redeemer will save me', 'God knows my name, God hears my cry, and God will answer me in the end', 'a', 'I know that my redeemer liveth, and...shall stand at the latter day upon the earth: And though after my skin worms destroy this body, yet in my flesh shall I see God: Whom I shall see for myself (Job 19:25-27).'),
('Job', 19, 'adults', 6, 'What does Job warn his friends about in Job 19:28-29?', 'If ye say, How we will persecute him...be ye afraid of the sword: for wrath bringeth the punishments of the sword, that ye may know there is a judgment', 'God will turn their own suffering back on them', 'Their children will bear the shame of their false counsel', 'God will remove their wisdom if they persist in accusation', 'a', 'But ye should say, Why persecute we him?...Be ye afraid of the sword: for wrath bringeth the punishments of the sword, that ye may know there is a judgment (Job 19:28-29).'),
('Job', 19, 'adults', 7, 'What is the theological significance of the Hebrew word go''el (redeemer/kinsman-redeemer) used in Job 19:25?', 'A go''el was a near kinsman who redeemed property or avenged blood; Job uses it of God as one who will personally vindicate his cause and stands as his nearest kin-advocate', 'It is simply a poetic name for God without legal meaning', 'It refers to an angelic being appointed to defend the righteous', 'It is the same word used for a sacrificial priest', 'a', 'Go''el (redeemer) in Job 19:25 carries the legal force of a kinsman-redeemer who restores, vindicates, and avenges — Job applies this title to God as his personal advocate.'),
('Job', 19, 'adults', 8, 'How does Job 19:25-27 function as a theological climax within the book and within Old Testament hope?', 'It represents the highest point of Job''s faith — a resurrection hope that transcends present suffering, and stands as one of the clearest Old Testament affirmations of bodily resurrection and personal vision of God', 'It is simply an expression of Job''s desire to be vindicated before he dies', 'It proves that all Old Testament saints believed in a physical resurrection', 'It anticipates only Job''s physical restoration in chapter 42', 'a', 'Job 19:25-27 is widely regarded as a proto-resurrection text — "yet in my flesh shall I see God" — offering bodily, personal, post-mortem hope that resonates with NT resurrection theology (cf. 1 Corinthians 15).');

-- ═══ Job Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 20, 'kids', 1, 'Who speaks in Job chapter 20?', 'Zophar the Naamathite', 'Bildad the Shuhite', 'Eliphaz the Temanite', 'Job himself', 'a', 'Then answered Zophar the Naamathite (Job 20:1) — this is Zophar''s second speech.'),
('Job', 20, 'kids', 2, 'What does Zophar say about the triumph of the wicked in Job 20:5?', 'The triumphing of the wicked is short, and the joy of the hypocrite but for a moment', 'The wicked man prospers all his days but perishes at last', 'The glory of the wicked is like the morning cloud', 'The wicked man''s victory lasts only a season', 'a', 'That the triumphing of the wicked is short, and the joy of the hypocrite but for a moment (Job 20:5).'),
('Job', 20, 'kids', 3, 'What does Zophar say God does to the wicked in Job 20:23?', 'God shall cast the fury of his wrath upon him', 'God will take away the wicked man''s children', 'God sends a plague to destroy the sinner', 'God removes his blessing from the wicked man''s house', 'a', 'When he is about to fill his belly, God shall cast the fury of his wrath upon him, and shall rain it upon him while he is eating (Job 20:23).'),
-- Teens
('Job', 20, 'teens', 1, 'How does Zophar describe the height to which the wicked man rises before his fall in Job 20:6-7?', 'Though his excellency mount up to the heavens and his head reach unto the clouds, yet he shall perish for ever like his own dung', 'The wicked man builds himself a great tower and then falls', 'His glory is like the eagle''s flight before the arrow strikes', 'The wicked rise above the mountains only to be cast to the sea', 'a', 'Though his excellency mount up to the heavens, and his head reach unto the clouds; Yet he shall perish for ever like his own dung (Job 20:6-7).'),
('Job', 20, 'teens', 2, 'What dream imagery does Zophar use for the wicked in Job 20:8?', 'He shall fly away as a dream, and shall not be found: yea, he shall be chased away as a vision of the night', 'The wicked man''s glory fades like a dream at dawn', 'His power passes as quickly as a sleeping man''s vision', 'The night swallows the wicked as it swallows dreams', 'a', 'He shall fly away as a dream, and shall not be found: yea, he shall be chased away as a vision of the night (Job 20:8).'),
('Job', 20, 'teens', 3, 'What does Zophar say about the sweetness of sin in the wicked man''s mouth in Job 20:12-13?', 'Though wickedness be sweet in his mouth, though he hide it under his tongue and spare it and keep it still within his mouth, yet his meat in his bowels is turned', 'The wicked man delights in sin like honey in his mouth', 'Sweet sin turns bitter before it is swallowed', 'The sinner savours every evil deed like a fine meal', 'a', 'Though wickedness be sweet in his mouth, though he hide it under his tongue; Though he spare it...yet his meat in his bowels is turned (Job 20:12-14).'),
('Job', 20, 'teens', 4, 'What does Zophar say the wicked man will vomit up in Job 20:15?', 'He hath swallowed down riches, and he shall vomit them up again: God shall cast them out of his belly', 'The wicked man spews out all the counsel he has received', 'The riches gained by sin become poison in his stomach', 'He returns all he has stolen to its rightful owners', 'a', 'He hath swallowed down riches, and he shall vomit them up again: God shall cast them out of his belly (Job 20:15).'),
('Job', 20, 'teens', 5, 'What weapon imagery does Zophar use for the fate of the wicked in Job 20:24-25?', 'He shall flee from the iron weapon, and the bow of steel shall strike him through; the glittering sword cometh out of his gall', 'God''s arrows of fire pursue the wicked man to his grave', 'The sword of judgment hangs above the sinner''s head', 'God draws his bow and the wicked man cannot escape', 'a', 'He shall flee from the iron weapon, and the bow of steel shall strike him through. It is drawn, and cometh out of the body; yea, the glittering sword cometh out of his gall (Job 20:24-25).'),
-- Adults
('Job', 20, 'adults', 1, 'What motivates Zophar to speak in Job 20:2-3?', 'His thoughts cause him to answer because he has heard the check of his reproach and the spirit of his understanding causeth him to answer', 'He is angry at Job''s latest words', 'He has received a new vision from God', 'He speaks out of compassion for Job''s family', 'a', 'Therefore do my thoughts cause me to answer, and for this I make haste. I have heard the check of my reproach, and the spirit of my understanding causeth me to answer (Job 20:2-3).'),
('Job', 20, 'adults', 2, 'What does Zophar say about the eye that saw the wicked man in Job 20:9?', 'The eye also which saw him shall see him no more; neither shall his place any more behold him', 'Those who loved him will turn their eyes away in shame', 'His place in the assembly shall be filled by another', 'His family shall forget his face within a generation', 'a', 'The eye also which saw him shall see him no more; neither shall his place any more behold him (Job 20:9).'),
('Job', 20, 'adults', 3, 'What does Zophar say about the children of the wicked in Job 20:10?', 'His children shall seek to please the poor, and his hands shall restore their goods', 'His children inherit his shame and his debt', 'The sons of the wicked shall be scattered among the nations', 'His children will deny his name to escape punishment', 'a', 'His children shall seek to please the poor, and his hands shall restore their goods (Job 20:10).'),
('Job', 20, 'adults', 4, 'What image does Zophar use of the adder''s tongue to describe the wicked man''s ill-gotten gains in Job 20:16?', 'He shall suck the poison of asps: the viper''s tongue shall slay him', 'The honey of wickedness turns to asp venom in the mouth', 'His profits are as deadly as the bite of a serpent', 'The wicked man''s wine is mixed with the poison of dragons', 'a', 'He shall suck the poison of asps: the viper''s tongue shall slay him (Job 20:16).'),
('Job', 20, 'adults', 5, 'What does Zophar say about the wicked man''s enjoyment of rivers and streams in Job 20:17?', 'He shall not see the rivers, the floods, the brooks of honey and butter', 'The rivers of blessing flow past his door but he receives nothing', 'God turns the streams aside before they reach the sinner', 'The wicked man drinks from polluted streams all his days', 'a', 'He shall not see the rivers, the floods, the brooks of honey and butter (Job 20:17).'),
('Job', 20, 'adults', 6, 'How does Zophar describe the tent of the wicked in Job 20:26?', 'All darkness shall be hid in his secret places: a fire not blown shall consume him; it shall go ill with him that is left in his tabernacle', 'His house stands empty in the wilderness', 'The wicked man''s tent catches fire in the night', 'Strangers occupy his dwelling after his death', 'a', 'All darkness shall be hid in his secret places: a fire not blown shall consume him; it shall go ill with him that is left in his tabernacle (Job 20:26).'),
('Job', 20, 'adults', 7, 'What cosmic witnesses does Zophar invoke against the wicked in Job 20:27?', 'The heaven shall reveal his iniquity; and the earth shall rise up against him', 'Sun, moon, and stars testify against the sinner', 'God''s angels carry the record of every wicked deed', 'The mountains and seas will cry out at the last day', 'a', 'The heaven shall reveal his iniquity; and the earth shall rise up against him (Job 20:27).'),
('Job', 20, 'adults', 8, 'What is the underlying theological assumption of Zophar''s entire speech in chapter 20, and why is it problematic in the context of Job''s situation?', 'Zophar assumes a strict doctrine of temporal retribution — the wicked always suffer quickly and visibly in this life — which the book of Job is specifically designed to challenge', 'Zophar is correct that God always punishes sin in this life', 'Zophar''s error is only that he applies his doctrine too harshly', 'Zophar is presenting Job 20 as a description of the last judgment, not earthly life', 'a', 'Zophar''s speech rests on the assumption that suffering = wickedness and prosperity = righteousness — precisely the oversimplification the book of Job deconstructs, as God himself will rebuke (Job 42:7).');

-- ═══ Job Chapter 21 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Job', 21, 'kids', 1, 'What big question does Job ask in Job 21:7?', 'Wherefore do the wicked live, become old, yea, are mighty in power?', 'Why do the righteous suffer so much?', 'When will God answer my prayers?', 'How long must I bear this pain?', 'a', 'Wherefore do the wicked live, become old, yea, are mighty in power? (Job 21:7).'),
('Job', 21, 'kids', 2, 'What do the wicked say to God in Job 21:14?', 'Depart from us; for we desire not the knowledge of thy ways', 'We will serve you only when things go well', 'We do not need to pray for we are already blessed', 'We will not listen to the words of thy prophets', 'a', 'Therefore they say unto God, Depart from us; for we desire not the knowledge of thy ways (Job 21:14).'),
('Job', 21, 'kids', 3, 'What does Job say about the house of the wicked man in Job 21:28?', 'Where is the house of the prince? and where are the dwelling places of the wicked?', 'The wicked man''s house will be destroyed in one day', 'The house of the wicked stands firm without God', 'The wicked man builds his house on sand', 'a', 'For ye say, Where is the house of the prince? and where are the dwelling places of the wicked? (Job 21:28).'),
-- Teens
('Job', 21, 'teens', 1, 'What does Job ask his friends to do before he speaks in Job 21:2?', 'Hear diligently my speech, and let this be your consolations', 'Sit in silence and let him present his case to God', 'Stop mocking him and listen without prejudice', 'Consider that God alone knows the truth of his suffering', 'a', 'Hear diligently my speech, and let this be your consolations (Job 21:2).'),
('Job', 21, 'teens', 2, 'What physical reaction does Job have when he considers the prosperity of the wicked in Job 21:6?', 'Even when I remember I am afraid, and trembling taketh hold on my flesh', 'My heart grows bitter and my eyes fill with tears', 'I am filled with anger at the injustice I see', 'My knees grow weak and my hands tremble', 'a', 'Even when I remember I am afraid, and trembling taketh hold on my flesh (Job 21:6).'),
('Job', 21, 'teens', 3, 'How does Job describe the prosperity of the wicked man''s household in Job 21:8-11?', 'Their seed is established in their sight with them, and their offspring before their eyes; their houses are safe, their bull gendereth, and their children dance and rejoice', 'The wicked man''s family is surrounded by blessings while the righteous weep', 'Their children grow tall and strong while the righteous mourn', 'The wicked man''s sons inherit great wealth without working', 'a', 'Their seed is established in their sight...Their houses are safe...Their bull gendereth, and faileth not...Their little ones dance (Job 21:8-11).'),
('Job', 21, 'teens', 4, 'How does Job describe the death of the wicked in Job 21:13?', 'They spend their days in wealth, and in a moment go down to the grave', 'The wicked man dies peacefully while the righteous suffer to the end', 'Without warning or punishment the wicked slip into the grave', 'The wicked enjoy a long life and die without regret', 'a', 'They spend their days in wealth, and in a moment go down to the grave (Job 21:13).'),
('Job', 21, 'teens', 5, 'What does Job say about the candle of the wicked in Job 21:17?', 'How oft is the candle of the wicked put out! and how oft cometh their destruction upon them!', 'The wicked man''s light burns long though it should be quenched', 'God puts out the candle of the wicked after a long delay', 'The candle of the wicked is never truly extinguished', 'a', 'How oft is the candle of the wicked put out! and how oft cometh their destruction upon them! God distributeth sorrows in his anger (Job 21:17).'),
-- Adults
('Job', 21, 'adults', 1, 'What does Job say will cause his friends to be astonished in Job 21:5?', 'Mark me, and be astonished, and lay your hand upon your mouth', 'Consider the justice of God before you condemn me', 'Look at my body and then say that I have sinned greatly', 'Think of your own lives before you judge mine', 'a', 'Mark me, and be astonished, and lay your hand upon your mouth (Job 21:5).'),
('Job', 21, 'adults', 2, 'What does Job observe about the wicked man''s children and his own fate in Job 21:19-21?', 'God layeth up his iniquity for his children; but the wicked man should be recompensed himself that he may know it, and his eyes shall see his destruction', 'The sins of the fathers are always visited on the children in this life', 'The wicked man escapes punishment but his children suffer instead', 'God delays judgment so that the wicked man may repent', 'a', 'God layeth up his iniquity for his children...but his own eyes shall see his destruction (Job 21:19-20).'),
('Job', 21, 'adults', 3, 'What does Job say about the wicked man''s attitude toward God in Job 21:15?', 'What is the Almighty, that we should serve him? and what profit should we have, if we pray unto him?', 'The wicked man denies God''s existence in his heart', 'God is only a useful tool to the wicked when they need help', 'The wicked man prays outwardly but curses God inwardly', 'a', 'What is the Almighty, that we should serve him? and what profit should we have, if we pray unto him? (Job 21:15).'),
('Job', 21, 'adults', 4, 'What does Job concede about the counsel of the wicked in Job 21:16?', 'Lo, their good is not in their hand: the counsel of the wicked is far from me', 'Though the wicked prosper, Job wants nothing to do with their ways', 'The wicked man''s advice is poisonous to all who follow it', 'Job admits that not every wicked man prospers as he has described', 'a', 'Lo, their good is not in their hand: the counsel of the wicked is far from me (Job 21:16).'),
('Job', 21, 'adults', 5, 'What image does Job use for the wicked before the wind in Job 21:18?', 'They are as stubble before the wind, and as chaff that the storm carrieth away', 'The wicked are swept away like leaves in autumn', 'God''s judgment blows the wicked like smoke from a fire', 'The wicked scatter before the storm like frightened birds', 'a', 'They are as stubble before the wind, and as chaff that the storm carrieth away (Job 21:18).'),
('Job', 21, 'adults', 6, 'What does Job say about where the wicked man is brought on the day of calamity in Job 21:30?', 'That the wicked is reserved to the day of destruction and shall be brought forth to the day of wrath', 'The wicked man is swallowed by the earth when his day comes', 'God gathers the wicked together for a final accounting', 'The day of calamity finds the wicked still trusting in their riches', 'a', 'That the wicked is reserved to the day of destruction? they shall be brought forth to the day of wrath (Job 21:30).'),
('Job', 21, 'adults', 7, 'How does Job describe the honorable burial of the wicked in Job 21:32-33?', 'Yet shall he be brought to the grave, and shall remain in the tomb. The clods of the valley shall be sweet unto him, and every man shall draw after him, as there are innumerable before him', 'The wicked man is buried without mourners or ceremony', 'His tomb is quickly forgotten and overgrown with weeds', 'The wicked man is refused burial and cast outside the city', 'a', 'Yet shall he be brought to the grave...The clods of the valley shall be sweet unto him, and every man shall draw after him (Job 21:32-33).'),
('Job', 21, 'adults', 8, 'How does Job 21 function as a direct theological counter to Zophar''s speech in Job 20?', 'Job 21 systematically dismantles the doctrine of immediate retribution by presenting empirical evidence that the wicked often prosper, live long, die in peace, and are buried with honor — the exact opposite of what Zophar predicted', 'Job 21 agrees with Zophar that the wicked eventually suffer but argues the timeline is longer', 'Job is only speaking rhetorically in chapter 21 and does not actually believe the wicked prosper', 'Job chapter 21 focuses only on Job''s personal situation rather than general principles of divine justice', 'a', 'Job 21 is a deliberate answer to chapters 18-20 — where Bildad and Zophar catalogue the wicked man''s swift ruin, Job counters: they live, grow mighty, die in peace, and are honored in burial (Job 21:7-33), exposing the friends'' oversimplification of divine justice.');
